def test_tc_gw_timeout_001_message_present(can_bus):
    msgs = collect_messages(can_bus, GW_FAULT_STATUS_ID, 2)
    assert msgs

def test_tc_gw_timeout_002_no_timeout_flags(can_bus):
    msgs = collect_messages(can_bus, GW_FAULT_STATUS_ID, 2)
    assert msgs
    for msg in msgs:
        assert decode_door_signal_timeout(msg) == 0
        assert decode_speed_signal_timeout(msg) == 0

def test_tc_gw_timeout_003_door_signal_timeout(can_bus):
    msgs = collect_messages(can_bus, GW_FAULT_STATUS_ID, 2)
    assert msgs
    for msg in msgs:
        assert decode_door_signal_timeout(msg) == 1

def test_tc_gw_timeout_004_speed_signal_timeout(can_bus):
    msgs = collect_messages(can_bus, GW_FAULT_STATUS_ID, 2)
    assert msgs
    for msg in msgs:
        assert decode_speed_signal_timeout(msg) == 1

def test_tc_gw_timeout_005_multiple_timeouts(can_bus):
    msgs = collect_messages(can_bus, GW_FAULT_STATUS_ID, 2)
    assert msgs
    for msg in msgs:
        assert decode_door_signal_timeout(msg) == 1
        assert decode_speed_signal_timeout(msg) == 1

def test_tc_gw_timeout_006_timeout_clear(can_bus):
    msgs = collect_messages(can_bus, GW_FAULT_STATUS_ID, 3)
    assert msgs
    for msg in msgs:
        assert decode_door_signal_timeout(msg) in (0, 1)
        assert decode_speed_signal_timeout(msg) in (0, 1)

def test_tc_gw_timeout_007_dlc_check(can_bus):
    msgs = collect_messages(can_bus, GW_FAULT_STATUS_ID, 2)
    assert msgs
    for msg in msgs:
        assert msg.dlc == GW_FAULT_STATUS_DLC
